import{_ as t,o as r,c as e,a6 as s,ko as n,kp as p,fI as i,l0 as o,kv as _}from"./chunks/framework.UYVGz2W_.js";const x=JSON.parse('{"title":"サムネイル","description":"","frontmatter":{},"headers":[],"relativePath":"ja/thumbnails/index.md","filePath":"ja/thumbnails/index.md"}'),l={name:"ja/thumbnails/index.md"};function d(m,a,c,h,g,f){return r(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="サムネイル" tabindex="-1">サムネイル <a class="header-anchor" href="#サムネイル" aria-label="Permalink to “サムネイル”">​</a></h1><h2 id="手動でサムネイルを追加" tabindex="-1">手動でサムネイルを追加 <a class="header-anchor" href="#手動でサムネイルを追加" aria-label="Permalink to “手動でサムネイルを追加”">​</a></h2><p>プレビューをサムネイルとして定義するには、プレビューがリビジョンとしてアップロードされている必要があります。</p><p>リストページで希望するステータスをクリックし、右パネルの<strong>[プレビュー]</strong>ボタン (1) をクリックします。</p><p><img src="'+n+'" alt="サムネイルボタン"></p><p>ボタンをクリックすると、最初のフレームまたは任意のフレームを選択できます。フレームを選択すると、サムネイルが表示され、ボタンはグレーに変わります。</p><p><img src="'+p+'" alt="サムネイル適用"></p><h2 id="サムネイルを自動的に追加する" tabindex="-1">サムネイルを自動的に追加する <a class="header-anchor" href="#サムネイルを自動的に追加する" aria-label="Permalink to “サムネイルを自動的に追加する”">​</a></h2><p>サムネイルを自動的に生成したい場合は、ナビゲーションメニューを使用して、本番環境から設定ページに移動します。</p><p><img src="'+i+'" alt="設定メニュー"></p><p><strong>パラメータ</strong>タブで、<strong>新しいプレビューを自動的にサムネイルとして設定する</strong>を選択します。</p><p><img src="'+o+'" alt="設定プレビュー自動"></p><p>作業が完了したら、変更を<strong>保存</strong>することをお忘れなく。これで、プレビューをアップロードすると、自動的にサムネイルとして使用されるようになります。</p><h2 id="プレビューの一括アップロード-サムネイルとして" tabindex="-1">プレビューの一括アップロード（サムネイルとして <a class="header-anchor" href="#プレビューの一括アップロード-サムネイルとして" aria-label="Permalink to “プレビューの一括アップロード（サムネイルとして”">​</a></h2><p>グローバルページにある<strong>[サムネイルを追加]</strong>ボタン ![サムネイルを追加]ボタン（../img/getting-started/add_thumbnails.png）を使用して、サムネイルを一括でインポートします。</p><p><img src="'+_+'" alt="履歴"></p><p>新しいポップアップが開き、サムネイルをどのタイプのタスクにリンクするかを選択するよう求められます。</p><p><strong>サムネイルの一括インポートでは、画像ファイルと動画ファイルの両方が受け入れられます</strong>。動画ファイルのサムネイルには、最初のフレームのみが使用されます。</p><p>サムネイルを正しいショットに自動的にリンクさせるには、サムネイルに「sequence_shot」という名前を付ける必要があります。</p><p>例えば、シーケンスの名前が「SEQ_001」、ショットの名前が「SH_001」の場合、サムネイルのファイル名は「SEQ_001_SH_001」となります。</p>',20)])])}const u=t(l,[["render",d]]);export{x as __pageData,u as default};
